-- Add evaluation_profile column to scenarios table
-- Used by eval system V2: per-lesson evaluation profile generated by Python engine
ALTER TABLE scenarios ADD COLUMN IF NOT EXISTS evaluation_profile TEXT;

-- Add V2 feedback columns to feedback table
-- critical_moment: { label, passed, evidence }
-- categories: { rapport, discovery, expertise, objections, communication, closing }
ALTER TABLE feedback ADD COLUMN IF NOT EXISTS critical_moment JSONB;
ALTER TABLE feedback ADD COLUMN IF NOT EXISTS categories JSONB;
